1388 void Instruction::copyMetadata(const Instruction &SrcInst,
1389                                ArrayRef<unsigned> WL) {
1390   if (WL.empty() || is_contained(WL, LLVMContext::MD_dbg))
1391     setDebugLoc(SrcInst.getDebugLoc().orElse(getDebugLoc()));
1392 
1393   if (!SrcInst.hasMetadata())
1394     return;
1395 
1396   SmallDenseSet<unsigned, 4> WLS(WL.begin(), WL.end());
1397 
1398   // Otherwise, enumerate and copy over metadata from the old instruction to the
1399   // new one.
1400   SmallVector<std::pair<unsigned, MDNode *>, 4> TheMDs;
1401   SrcInst.getAllMetadataOtherThanDebugLoc(TheMDs);
1402   for (const auto &MD : TheMDs) {
1403     if (WL.empty() || WLS.count(MD.first))
1404       setMetadata(MD.first, MD.second);
1405   }
1406 }
